sys_script.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// STRY0065506 - Keep template in sync with top template task
	// See also 'Template - onUpdate - Sync Top TempTask ' this rule is the partner rule to keep the field values in sync

	// only update Template if changes were made to the Top Template Task
	if(current.parent.nil()){
		var recTemplate = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
		if(recTemplate.get(current.tasker_process_definition)){
			// STRY0065506 - go through each sync field and set any changes
			var updateTemplate = false;

			// STRY0084986
			if(current.tasker_type != previous.tasker_type){
				updateTemplate = true;
				recTemplate.u_tasker_type = current.tasker_type;
			}
			if(current.u_signature_instructions != previous.u_signature_instructions){
				updateTemplate = true;
				recTemplate.u_signature_instructions = current.u_signature_instructions;
			}
			if(current.u_reviewer != previous.u_reviewer){
				updateTemplate = true;
				recTemplate.u_reviewer = current.u_reviewer;
			}
			if(current.provide_response != previous.provide_response){
				updateTemplate = true;
				recTemplate.provide_response = current.provide_response;
			}
			if(current.u_on_behalf_of != previous.u_on_behalf_of){
				updateTemplate = true;
				recTemplate.u_on_behalf_of = current.u_on_behalf_of;
			}

			if(current.short_description != previous.short_description){
				updateTemplate = true;
				recTemplate.short_description = current.short_description;
			}
			if(current.instructions != previous.instructions){
				updateTemplate = true;
				recTemplate.description = current.instructions;
			}
			if(current.u_objective != previous.u_objective){
				updateTemplate = true;
				recTemplate.u_objective = current.u_objective;
			}
			if(current.classification != previous.classification){
				updateTemplate = true;
				recTemplate.classification = current.classification;
			}
			if(current.primary_assignee != previous.primary_assignee){
				updateTemplate = true;
				recTemplate.u_primary_assignee = current.primary_assignee;
			}
			if(current.primary_office != previous.primary_office){
				updateTemplate = true;
				recTemplate.u_primary_office = current.primary_office;
			}
			if(current.assigned_to_group != previous.assigned_to_group){
				updateTemplate = true;
				recTemplate.u_restricted_group = current.assigned_to_group;
			}
			if(current.tasking_authority != previous.tasking_authority){
				updateTemplate = true;
				recTemplate.u_tasking_authority = current.tasking_authority;
			}

			if(current.assigned_to_individual != previous.assigned_to_individual){
				updateTemplate = true;
				recTemplate.u_assigned_member = current.assigned_to_individual;
			}
			// STRY0075863
			if(current.u_external_ou != previous.u_external_ou){
				updateTemplate = true;
				recTemplate.u_external_ou = current.u_external_ou;
			}
			if(current.poc_name != previous.poc_name){
				updateTemplate = true;
				recTemplate.poc_name = current.poc_name;
			}
			if(current.outbound != previous.outbound){
				updateTemplate = true;
				recTemplate.outbound = current.outbound;
			}
			if(current.u_internal_contact != previous.u_internal_contact){
				updateTemplate = true;
				recTemplate.u_internal_contact = current.u_internal_contact;
			}
			if(current.u_internal_contact_performing_task != previous.u_internal_contact_performing_task){
				updateTemplate = true;
				recTemplate.u_internal_contact_performing_task = current.u_internal_contact_performing_task;
			}

			// STRY0076610
			if(current.u_wait_for_subtasks_to_finish != previous.u_wait_for_subtasks_to_finish){
				updateTemplate = true;
				recTemplate.u_wait_for_subtasks_to_finish = current.u_wait_for_subtasks_to_finish;
			}

			// STRY0076609
			if(current.duration != previous.duration){
				updateTemplate = true;
				recTemplate.u_duration = current.duration;
			}
			if(current.warning_hours != previous.warning_hours){
				updateTemplate = true;
				recTemplate.u_warning_days = current.warning_hours;
			}

			// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
			// when this was added, had to change to always save to simplify for now
			updateTemplate = true;
			recTemplate = new CustomTaskerFieldHelper().mapFieldDataOnAction('templateTaskSyncTemplate', current, recTemplate);

			// if any of the sync fields changed, then udpate the Top Template Task, otherwise do not
			// The Top Template Task is also checking these values and updating the Template record
			// When that happens, the buisness rule may fire again.  If it does, the before and after should be the same.
			// this will prevent a recursive loop.
			if(updateTemplate){
				// don't run this update method again when the Top Template Task updates it' fields
				recTemplate.update();
			}
		}
	}
})(current, previous);
